def expand_ranges(s):
    result = []
    s = s.strip()
    if not s:
        return result
    for part in s.split(','):
        part = part.strip()
        if '-' in part:
            start_str, end_str = part.split('-', 1)
            start = int(start_str)
            end = int(end_str)
            result.extend(range(start, end + 1))
        else:
            result.append(int(part))
    return result
